import{_ as e,o as a,c as s,a7 as r}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Resource Stages","description":"","frontmatter":{},"headers":[],"relativePath":"en/stages/resource.md","filePath":"en/stages/resource.md","lastUpdated":1775394001000}'),i={name:"en/stages/resource.md"};function l(o,t,d,n,u,c){return a(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="resource-stages" tabindex="-1">Resource Stages <a class="header-anchor" href="#resource-stages" aria-label="Permalink to &quot;Resource Stages&quot;">​</a></h1><p>Resource stages are the primary source of upgrade materials in Morimens. They are available daily and consume Menophine (stamina).</p><h2 id="resource-stage-types" tabindex="-1">Resource Stage Types <a class="header-anchor" href="#resource-stage-types" aria-label="Permalink to &quot;Resource Stage Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stage</th><th>Type</th><th>Reset</th><th>Unlock</th><th>Drops</th></tr></thead><tbody><tr><td>Dissolution Ruins</td><td>Material Dungeon</td><td>Daily</td><td>Clear Investigation 1-2</td><td>Ascension Caskets, Skill Supplies, Domain Residues, Edification Materials, Rose Scrip, Gnosis Elixirs, Breakthrough Materials</td></tr><tr><td>Forbidden Inscriptions</td><td>Material Dungeon</td><td>Daily</td><td>Post-clear repeat</td><td>Various upgrade materials</td></tr><tr><td>Transcendent Existence</td><td>Weekly Boss</td><td>Weekly (Monday 15:00)</td><td>Story progression</td><td>Rich rewards -- clear weekly for best value</td></tr></tbody></table><h2 id="dissolution-ruins-details" tabindex="-1">Dissolution Ruins Details <a class="header-anchor" href="#dissolution-ruins-details" aria-label="Permalink to &quot;Dissolution Ruins Details&quot;">​</a></h2><p>The Dissolution Ruins are the main material farming location. They consume Menophine (stamina) to enter and contain two subtypes:</p><ul><li><strong>Ascension Material Runs</strong> -- Drop Ascension Caskets and Breakthrough Materials</li><li><strong>Skill Material Runs</strong> -- Drop Skill Supplies and Domain Residues</li></ul><p>Each realm has its own Dissolution Ruins variant:</p><table tabindex="0"><thead><tr><th>Realm</th><th>Dungeon Name</th><th>Exclusive Drop</th></tr></thead><tbody><tr><td><span class="realm-badge realm-chaos">Chaos</span></td><td>Chaos Dissolution Ruins</td><td>Chaotic Residue</td></tr><tr><td><span class="realm-badge realm-aequor">Aequor</span></td><td>Aequor Dissolution Ruins</td><td>Abyssal Residue</td></tr><tr><td><span class="realm-badge realm-caro">Caro</span></td><td>Caro Dissolution Ruins</td><td>Bloody Residue</td></tr><tr><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Ultra Dissolution Ruins</td><td>Cosmic Residue</td></tr></tbody></table><h2 id="daily-weekly-system" tabindex="-1">Daily / Weekly System <a class="header-anchor" href="#daily-weekly-system" aria-label="Permalink to &quot;Daily / Weekly System&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Activity</th><th>Reset</th><th>Rewards</th></tr></thead><tbody><tr><td>Daily Training</td><td>Daily</td><td>500 EXP/day. Can use proxy certificates for quick completion (max 5x).</td></tr><tr><td>Weekly Trial</td><td>Weekly</td><td>Silver 100/150/250 + D-Jewels</td></tr><tr><td>Outfield Agent (Assignments)</td><td>Daily settlement</td><td>Rose Scrip, D-Jewels, various materials. Research: Recipe compendium tasks yield 4,000 base + 2,000 per 20-level gap Rose Scrip.</td></tr><tr><td>Curriculum</td><td>Ongoing</td><td>Rose Scrip, Mimetic Crystal, Thousand-Face Seals</td></tr></tbody></table><h2 id="farming-priority" tabindex="-1">Farming Priority <a class="header-anchor" href="#farming-priority" aria-label="Permalink to &quot;Farming Priority&quot;">​</a></h2><ol><li><strong>Skill materials</strong> -- Skill levels have the biggest impact on combat performance.</li><li><strong>Awakener EXP</strong> -- Level your core team to at least 25 for skill unlocks.</li><li><strong>Ascension materials</strong> -- Required to break level caps.</li><li><strong>Edification materials</strong> -- For character trait upgrades.</li><li><strong>Clear Transcendent Existence weekly</strong> -- Rich rewards that should not be missed.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>All main story stages have 3-star rating rewards worth 50 Silver each, totaling up to 4,750 Silver across all stages. Clearing a higher difficulty automatically unlocks lower difficulty 3-star rewards.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Stages Overview</a></li><li><a href="./../items/materials.html">Materials</a></li><li><a href="./../awakeners/leveling.html">Leveling Guide</a></li><li><a href="./../cards/upgrade.html">Card Upgrades</a></li><li><a href="./../guides/dailies.html">Daily Tasks</a></li></ul>',16)])])}const p=e(i,[["render",l]]);export{m as __pageData,p as default};
